class Solution:
    def minBitFlips(self, start, goal):
        x = start ^ goal
        count = 0
        while x:
            count += x & 1
            x >>= 1
        return count

solutions.python:
class Solution:
    def minBitFlips(self, start, goal):
        return bin(start ^ goal).count('1')

solutions.javascript:
var minBitFlips = function(start, goal) {
    let x = start ^ goal;
    let count = 0;
    while (x !== 0) {
        count += x & 1;
        x >>>= 1;
    }
    return count;
};
